	sealGenerationInfo := &SealGenerationInfo{
		Generation: generation,
	}
	sealGenerationInfo.SetRewrapped(rewrapped)
	ctx := context.Background()
	for _, sealInfo := range sealInfos {
		typ, err := sealInfo.Wrapper.Type(ctx)
		if err != nil {
			return nil, err
		}
